+    for effect in &result.pending_effects {
+        prop_assert!(
+            DRAWER_EFFECTS.contains(&effect.name),
+            "unexpected drawer effect: {:?}",
+            effect.name
+        );
+        prop_assert!(effect.metadata.is_none());
